<h2 class="fw-bold mb-3">Quản lý đơn hàng</h2><div class="card-soft p-3"><table class="table align-middle"><thead><tr><th>Mã</th><th>Khách</th><th>Tổng</th><th>Trạng thái</th><th>Cập nhật</th></tr></thead><tbody><?php foreach($orders as $o): ?><tr><td><?php echo htmlspecialchars($o->order_code ?: $o->id, ENT_QUOTES, 'UTF-8'); ?></td><td><?php echo htmlspecialchars($o->name, ENT_QUOTES, 'UTF-8'); ?><br><small><?php echo htmlspecialchars($o->phone, ENT_QUOTES, 'UTF-8'); ?></small></td><td><?php echo number_format((float)$o->final_amount,0,',','.'); ?>đ</td><td><?php echo htmlspecialchars($o->order_status, ENT_QUOTES, 'UTF-8'); ?> / <?php echo htmlspecialchars($o->payment_status, ENT_QUOTES, 'UTF-8'); ?></td><td><form class="d-flex gap-2" method="post" action="<?php echo BASE_URL; ?>/Admin/updateOrder/<?php echo $o->id; ?>"><select name="order_status" class="form-select form-select-sm"><option value="pending">pending</option><option value="confirmed">confirmed</option><option value="shipping">shipping</option><option value="completed">completed</option><option value="cancelled">cancelled</option></select><select name="payment_status" class="form-select form-select-sm"><option value="unpaid">unpaid</option><option value="paid">paid</option><option value="refunded">refunded</option></select><input name="note" class="form-control form-control-sm" placeholder="Ghi chú"><button class="btn btn-sm btn-primary">Lưu</button></form></td></tr><?php endforeach; ?></tbody></table></div>

